// // This is a 16-bit wide 2-to-1 demultiplexer. Selects between two 16-bit outputs (A and B) based on a 1-bit select signal (sel). Output (Y) is the deselected input.
module mux_2_to_1 (  
    input [15:0] A,  
    input [15:0] B,  
    input sel,  
    output reg [15:0] Y  
);  
    always @(*) begin  
        if (sel)  
            Y = B;  
        else  
            Y = A;  
    end  
endmodule
